import requests

def solve(*args):
    if not args:
        return None

    # Assuming args is a list of IDs to fetch data from the JSON server
    results = []
    for arg in args:
        response = requests.get(f'http://localhost:3000/data/{arg}')
        if response.status_code == 200:
            results.append(response.json())
        else:
            results.append(None)

    return results
